/**
 * @fileoverview Alert component — modular entry point.
 * @module module/Alert
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { AlertDef as DEF } from '../Alert.def.js';

import { DEFAULTS, CLS, PART } from './constants.js';
import { SM_EFFECTS, setupDOM, cleanupDOM } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';

const Alert = class {
    #root     = null;
    #destroyed = false;
    #sm       = null;
    #config   = {};
    #eventAC  = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Alert: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    #init() {
        const root = this.#root;
        const config = this.#config;

        const { closeBtn } = setupDOM(root, config);

        const sm = new StateMachine({
            ...DEF.states,
            effects: SM_EFFECTS,
        }, { root });
        this.#sm = sm;

        if (closeBtn) {
            const ac = new AbortController();
            const opts = { signal: ac.signal };
            closeBtn[0].addEventListener('click', () => this.close(), opts);
            closeBtn[0].addEventListener('keydown', (e) => {
                if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); this.close(); }
            }, opts);
            this.#eventAC = ac;
        }
    }

    show() { this.#sm.send('SHOW'); emitEvent(this.#root[0], 'show'); }

    close() {
        this.#sm.send('HIDE');
        emitEvent(this.#root[0], 'hide');
        this.#config.onClose?.();
    }

    getControl() {
        const self = this;
        const variantMap = { info: PART.INFO, success: PART.SUCCESS, warning: PART.WARNING, danger: PART.DANGER };
        return {
            get variant()  { return self.#config.variant; },
            set variant(v) {
                const old = self.#config.variant;
                if (variantMap[old]) self.#root.removeClass(variantMap[old]);
                self.#config.variant = v;
                if (variantMap[v]) { self.#root.addClass(variantMap[v]); variantMap[v].apply(self.#root); }
            },
            get closable() { return self.#config.closable; },
            set closable(v){ self.#config.closable = !!v; },
            show:    () => self.show(),
            close:   () => self.close(),
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        cleanupDOM(this.#root);
    }
};

export default Alert;
